// // This module performs a bitwise OR operation on the 32-bit input data and the 16-bit mask when the enable signal is high, otherwise it returns the most significant 16 bits of the input data.
module top_module(
  input [31:0] data_in,
  input [15:0] mask,
  input enable,
  output [15:0] data_out
);reg [15:0] temp_data_out;

  always @(*) begin
    if (enable) begin
      temp_data_out = data_in & mask;
    end else begin
      temp_data_out = 16'b0;
    end
  end

  assign data_out = temp_data_out;

endmodule
